import AVFoundation
import SwiftUI

class AudioRecorder: NSObject, ObservableObject, AVAudioRecorderDelegate {
    @Published var isRecording = false
    @Published var recordings: [RecordingItem] = []
    @Published var permissionGranted = false

    private var recorder: AVAudioRecorder?

    struct RecordingItem: Identifiable, Codable, Hashable {
        let id: UUID
        let filename: String
        let date: Date
        var url: URL {
            FileManager.default.urls(for: .documentDirectory, in: .userDomainMask)[0]
                .appendingPathComponent(filename)
        }
    }

    func requestPermission() {
        AVAudioSession.sharedInstance().requestRecordPermission { [weak self] granted in
            DispatchQueue.main.async { self?.permissionGranted = granted }
        }
    }

    func startRecording() {
        let session = AVAudioSession.sharedInstance()
        do {
            try session.setCategory(.playAndRecord, mode: .default)
            try session.setActive(true)
        } catch {
            return
        }

        let filename = "recording-\(Date().timeIntervalSince1970).m4a"
        let url = FileManager.default.urls(for: .documentDirectory, in: .userDomainMask)[0]
            .appendingPathComponent(filename)

        let settings: [String: Any] = [
            AVFormatIDKey: Int(kAudioFormatMPEG4AAC),
            AVSampleRateKey: 44100,
            AVNumberOfChannelsKey: 1,
            AVEncoderAudioQualityKey: AVAudioQuality.high.rawValue
        ]

        do {
            recorder = try AVAudioRecorder(url: url, settings: settings)
            recorder?.delegate = self
            recorder?.record()
            isRecording = true
        } catch {
            return
        }
    }

    func stopRecording() {
        recorder?.stop()
        isRecording = false
        if let url = recorder?.url {
            let item = RecordingItem(id: UUID(), filename: url.lastPathComponent, date: Date())
            recordings.append(item)
            saveRecordings()
        }
    }

    func deleteRecording(_ item: RecordingItem) {
        try? FileManager.default.removeItem(at: item.url)
        recordings.removeAll { $0.id == item.id }
        saveRecordings()
    }

    private func saveRecordings() {
        if let data = try? JSONEncoder().encode(recordings) {
            UserDefaults.standard.set(data, forKey: "saved_recordings")
        }
    }

    func loadRecordings() {
        guard let data = UserDefaults.standard.data(forKey: "saved_recordings"),
              let items = try? JSONDecoder().decode([RecordingItem].self, from: data) else { return }
        recordings = items.filter { FileManager.default.fileExists(atPath: $0.url.path) }
    }
}

